import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface MacrosBreakdown {
  macro: string;
  value: number;
}

interface NutritionData {
  caloriesConsumed: number;
  macros: {
    carbohydrates: number;
    proteins: number;
    fats: number;
  };
  mealCount: {
    breakfast: number;
    lunch: number;
    dinner: number;
    snacks: number;
  };
  macrosBreakdown: MacrosBreakdown[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const nutritionData = response.data as NutritionData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: metaData.primaryColor }}>
              Nutrition Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Calories Consumed
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              {nutritionData.caloriesConsumed}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Meals
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {Object.entries(nutritionData.mealCount).map(([meal, count], index) => (
                <Chip
                  key={index}
                  label={`${meal.charAt(0).toUpperCase() + meal.slice(1)}: ${count}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <PieChart
            height={150}
            series={[
              {
                data: nutritionData.macrosBreakdown.map((macro) => ({ label: macro.macro, value: macro.value })),
                color: metaData.accentColor,
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 1.5,
                stroke: '#FFF',
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
